import { Vex } from '@vex_dev/sdk';

const vex = new Vex({
  projectId: 'vex_ecom_n8n',
  webhookToken: process.env.VEX_WEBHOOK_TOKEN
});

// n8n webhook node code
const validateAgentOutput = async (items: any[]) => {
  for (const item of items) {
    const result = await vex.validate({
      framework: 'n8n',
      inputs: {
        aiOutput: item.json.aiResponse,
        productData: item.json.productCatalog,
        customerContext: item.json.userSession
      },
      policy: {
        pricing: { mustMatchCatalog: true },
        claims: { requireSubstantiation: true },
        pii: { redact: true }
      }
    });

    if (!result.valid) {
      throw new Error(`Vex blocked: ${result.violations[0].message}`);
    }

    item.json.validatedOutput = result.cleanOutput;
  }
  return items;
};

import { Vex } from '@vex_dev/sdk';

const recursionGuard = new Vex({
  projectId: 'vex_ecom_n8n',
  counters: ['workflow-depth']
});

// Add to AI agent trigger webhook
const checkRecursion = async (items: any[]) => {
  const workflowId = $execution.id;
  const depth = await recursionGuard.increment('workflow-depth', workflowId);

  if (depth > 5) {
    throw new Error('Recursive execution blocked by Vex - max depth exceeded');
  }

  // Validate AI output
  for (const item of items) {
    const validation = await recursionGuard.validate({
      inputs: item.json,
      safeguards: {
        recursion: { maxDepth: 5 },
        rateLimit: { maxCalls: 100, window: '1m' }
      }
    });

    if (!validation.pass) {
      await recursionGuard.reset('workflow-depth', workflowId);
      return [];
    }
  }

  return items;
};

// n8n Code Node after Payment AI Agent
import { Vex } from '@vex_dev/sdk';

const pciGuard = new Vex({ projectId: 'vex_ecom_payments' });

const securePaymentCall = async (items: any[]) => {
  for (const item of items) {
    const toolCall = item.json.agentToolCall;

    // Vex PCI validation
    const result = await pciGuard.validate({
      framework: 'n8n',
      inputs: {
        toolParams: toolCall.parameters,
        operation: toolCall.name // 'createPayment', 'refund', etc.
      },
      policy: {
        pci: {
          maskFields: ['cardNumber', 'cvv', 'apiKey'],
          requireTokenization: true
        },
        pricing: { accuracyThreshold: 0.01 }
      }
    });

    if (result.valid) {
      item.json.securedParams = result.cleanInputs;
    } else {
      item.json.error = 'PCI violation blocked by Vex';
      continue;
    }
  }
  return items.filter(item => !item.json.error);
};
